#include <iostream>
#include <vector>
#include <algorithm>
#include <string>

using namespace std;

int main()
{
    vector<pair<string, int>> students = {{"Aman", 88}, {"Priya", 95}, {"Zara", 72}};

    sort(students.begin(), students.end(), [](pair<string, int> a, pair<string, int> b) {
        return a.second > b.second; // sort by marks, DESCENDING
    });

    for (auto s : students)
    {
        cout << s.first << ": " << s.second << endl;
    }

    return 0;
}

